// Wait times TSV — hourly points, code interpolates between them.
SAMPLE.waitsTSV = (function () {
  const profile = {
    pirates: [15, 25, 40, 55, 60, 55, 45, 40, 45, 50, 45, 35, 25],
    jungle:  [10, 20, 35, 45, 55, 50, 45, 40, 40, 45, 40, 30, 20],
    tianas:  [20, 40, 55, 70, 85, 80, 70, 65, 70, 75, 65, 50, 35],
    big_thunder: [15, 30, 45, 60, 70, 65, 55, 50, 55, 60, 50, 40, 25],
    haunted: [10, 20, 30, 45, 50, 50, 45, 40, 45, 50, 45, 35, 25],
    peter:   [30, 45, 60, 75, 85, 80, 75, 70, 75, 80, 70, 55, 40],
    small_world:   [5,  10, 15, 25, 30, 30, 25, 20, 25, 30, 25, 20, 15],
    space:   [20, 35, 50, 65, 75, 70, 60, 55, 60, 70, 60, 45, 30],
    buzz_lightyear:    [10, 15, 25, 35, 40, 40, 35, 30, 35, 40, 35, 25, 20]
  };
  const lines = ["attraction_id\ttime_of_day\tavg_wait_minutes"];
  for (const id in profile) {
    profile[id].forEach((w, i) => {
      const hh = String(9 + i).padStart(2, "0");
      lines.push(id + "\t" + hh + ":00\t" + w);
    });
  }
  return lines.join("\n");
})();
